import \'package:flutter/material.dart\';\nimport \'package:myapp/budget/models/budget.dart\';\nimport \'package:myapp/insights/models/financial_insight.dart\';\nimport \'package:myapp/transaction/models/transaction.dart\';\nimport \'package:uuid/uuid.dart\';\n\nclass FinancialInsightService {\n  final List<Transaction> transactions;\n  final List<Budget> budgets;\n  final _uuid = const Uuid();\n\n  FinancialInsightService(this.transactions, this.budgets);\n\n  List<FinancialInsight> generateInsights() {\n    final insights = <FinancialInsight>[\n      ..._generateSpendingPatternInsights(),\n      ..._generateBudgetRecommendationInsights(),\n      ..._generateOverspendingWarningInsights(),\n      ..._generateSavingsSuggestionInsights(),\n      _generateMonthlySummaryInsight(),\n    ];\n    return insights;\n  }\n\n  List<FinancialInsight> _generateSpendingPatternInsights() {\n    // In a real app, this would be a more sophisticated analysis\n    final insights = <FinancialInsight>[];\n    final categorySpending = <String, double>{};\n    for (var t in transactions) {\n      categorySpending.update(t.category, (value) => value + t.amount,\n          ifAbsent: () => t.amount);\n    }\n\n    final sortedCategories = categorySpending.entries.toList()\n      ..sort((a, b) => b.value.compareTo(a.value));\n\n    if (sortedCategories.isNotEmpty) {\n      final topCategory = sortedCategories.first;\n      insights.add(\n        FinancialInsight(\n          id: _uuid.v4(),\n          type: InsightType.spendingPattern,\n          title: \'Top Spending Category\',\n          description:\n              \'You spent the most on ${topCategory.key} this month: \$${topCategory.value.toStringAsFixed(2)}\',\n          date: DateTime.now(),\n          icon: Icons.pie_chart,\n          color: Colors.blue,\n        ),\n      );\n    }\n\n    return insights;\n  }\n\n  List<FinancialInsight> _generateBudgetRecommendationInsights() {\n    final insights = <FinancialInsight>[];\n    // Example: Recommend a budget for a category with high spending but no budget\n    final categoriesWithBudget = budgets.map((b) => b.category).toSet();\n    final categoriesWithHighSpending = transactions\n        .where((t) => t.amount > 100) // Example threshold\n        .map((t) => t.category)\n        .toSet();\n\n    final recommendations = categoriesWithHighSpending.difference(categoriesWithBudget);\n    for (var category in recommendations) {\n      insights.add(\n        FinancialInsight(\n          id: _uuid.v4(),\n          type: InsightType.budgetRecommendation,\n          title: \'Budget Recommendation\',\n          description: \'Consider setting a budget for the \\\'$category\\\' category.\',\n          date: DateTime.now(),\n          icon: Icons.recommend,\n          color: Colors.green,\n        ),\n      );\n    }\n    return insights;\n  }\n\n  List<FinancialInsight> _generateOverspendingWarningInsights() {\n    final insights = <FinancialInsight>[];\n    for (var budget in budgets) {\n      final spent = transactions\n          .where((t) => t.category == budget.category)\n          .fold(0.0, (sum, t) => sum + t.amount);\n      if (spent > budget.amount) {\n        insights.add(\n          FinancialInsight(\n            id: _uuid.v4(),\n            type: InsightType.overspendingWarning,\n            title: \'Overspending Warning\',\n            description:\n                \'You have overspent in the \\\'${budget.category}\\\' category by \$${(spent - budget.amount).toStringAsFixed(2)}.\',\n            date: DateTime.now(),\n            icon: Icons.warning,\n            color: Colors.orange,\n          ),\n        );\n      }\n    }\n    return insights;\n  }\n\n  List<FinancialInsight> _generateSavingsSuggestionInsights() {\n    // Example: Suggest saving by reducing spending in a non-essential category\n    final insights = <FinancialInsight>[];\n    final nonEssentialSpending = transactions\n        .where((t) => t.category == \'Entertainment\') // Example category\n        .fold(0.0, (sum, t) => sum + t.amount);\n\n    if (nonEssentialSpending > 200) {\n      insights.add(\n        FinancialInsight(\n          id: _uuid.v4(),\n          type: InsightType.savingsSuggestion,\n          title: \'Savings Suggestion\',\n          description:\n              \'You can save more by reducing your spending on Entertainment.\',\n          date: DateTime.now(),\n          icon: Icons.savings,\n          color: Colors.purple,\n        ),\n      );\n    }\n    return insights;\n  }\n\n  FinancialInsight _generateMonthlySummaryInsight() {\n    final totalSpending = transactions.fold(0.0, (sum, t) => sum + t.amount);\n    return FinancialInsight(\n      id: _uuid.v4(),\n      type: InsightType.monthlySummary,\n      title: \'Monthly Financial Summary\',\n      description:\n          \'You have spent a total of \$${totalSpending.toStringAsFixed(2)} this month.\',\n      date: DateTime.now(),\n      icon: Icons.summarize,\n      color: Colors.teal,\n    );\n  }\n}\n